def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        decay_rates = [0.8, 0.6, 0.4, 0.9, 0.5]
        weights = [1.2, 0.9, 1.5, 0.7, 1.1]
        penalties = 0
        depth_range = range(1, 8)
        for depth in depth_range:
            decay_idx = depth % len(decay_rates)
            weight_idx = depth % len(weights)
            decay = decay_rates[decay_idx]
            weight = weights[weight_idx]
            if residual <= 0:
                score += (25 / depth) * np.exp(-depth / 4)
            else:
                score += ((1 / residual) ** 1.1) * (depth ** 1.3) * weight
            residual *= decay
        if capacity > 5 * item:
            score *= 0.65
        elif capacity > 4 * item:
            score *= 0.75
        elif capacity > 2.5 * item:
            score *= 0.9
        elif capacity > 1.2 * item:
            score *= 1.1
        else:
            score *= 1.4
        for check in range(1, int(np.ceil(item)) + 5):
            mod_val = (capacity + check) % (check + 2)
            if mod_val == 0:
                penalties += 0.4 * (check ** 1.3)
            elif mod_val % 3 == 0:
                penalties -= 0.25 * (check ** 1.2)
            else:
                penalties += 0.15 * (check ** 0.95)
        score += penalties
        extra_penalty = 0
        for j in range(1, 4):
            tmp = ((capacity / (j + 1)) + (item * j)) % (j + 3)
            if tmp < 1:
                extra_penalty += j * 2
            elif tmp < 2:
                extra_penalty -= j * 1.5
            else:
                extra_penalty += j
        score += extra_penalty
        if score < 0:
            priorities[i] = 0
        elif score > 250:
            priorities[i] = 250
        else:
            priorities[i] = score
    return priorities
